// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

// Get the order data from the webhook
const order = $input.first().json;

// Calculate order totals
const itemsSubtotal = order.items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
const totalDiscount = order.items.reduce((sum, item) => sum + item.discount, 0);
const orderTotal = itemsSubtotal - totalDiscount + order.shippingCost;

// Check if high value order (>300)
const isHighValue = orderTotal > 300;
const priority = isHighValue ? 'high' : 'standard';
const requiresApproval = isHighValue;

// Process each item with category-based department assignment
const processedItems = order.items.map(item => {
  let handledBy = '';

  // Route by category
  switch(item.category) {
    case 'Electronics':
      handledBy = 'Electronics Department';
      break;
    case 'Sports':
      handledBy = 'Sports Department';
      break;
    case 'Home & Kitchen':
      handledBy = 'Home & Kitchen Department';
      break;
    default:
      handledBy = 'General Department';
  }

  return {
    ...item,
    handledBy: handledBy,
    processingTime: new Date().toISOString(),
    priority: priority,
    requiresApproval: requiresApproval,
    orderTotal: orderTotal,
    itemsSubtotal: itemsSubtotal,
    totalDiscount: totalDiscount
  };
});

// Return all processed items
return processedItems.map(item => ({ json: item }));
